import React, { useState } from "react";
import "./DropCourse.css";
import Navbar from "../components/navbar";
import axios from "axios";

function DropCourse() {
  const [studentId, setStudentId] = useState("");
  const [courseCode, setCourseCode] = useState("");
  const [reason, setReason] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post("http://localhost:5000/dropcourse", {
        studentId,
        CourseId,
        reason
      });

      alert("✅ " + res.data.message);

      // Reset form
      setStudentId("");
      setCourseCode("");
      setReason("");
    } catch (err) {
      console.error("Error dropping course:", err);
      alert(err.response?.data?.message || "Error dropping course");
    }
  };

  return (
    <>
      <Navbar />
      <form className="drop-form" onSubmit={handleSubmit}>
        <h2>Drop Course</h2>

        <label>Student ID</label>
        <input
          type="text"
          value={studentId}
          onChange={(e) => setStudentId(e.target.value)}
          required
        />

        <label>Course Code</label>
        <input
          type="text"
          value={courseCode}
          onChange={(e) => setCourseCode(e.target.value)}
          required
        />

        <label>Reason</label>
        <textarea
          value={reason}
          onChange={(e) => setReason(e.target.value)}
          required
        />

        <button type="submit">Drop Course</button>
      </form>
    </>
  );
}

export default DropCourse;
